def check_model_evaluation_or_training(node):
    if not any(
        (node['name'] == 'eval' and 'ModelEval' in node['value']['__module__'])
        or (node['name'] == 'train' and 'ModelTrain' in node['value']['__module__'])
        or (node['name'] == 'load_state_dict' and not any(
            (node['args'][0]['value']['name'] == 'self')
            and ('ModelEval' in node['args'][0]['args'][0]['value']['__module__'])
            or ('ModelTrain' in node['args'][0]['args'][0]['value']['__module__'])
        ))
    ):
        return True
    return False
